    /* Initialize data */
    data = NULL;
    data = (char *)malloc(100*sizeof(char));
    if (data == NULL) {exit(-1);}
    memset(data, 'A', 100-1);
    data[100-1] = '\0';
    /* FIX: Use data before freeing it */
    printLine(data);
    free(data);
}
```

## GLOBAL FIX:

Implement a smart pointer or resource management pattern that enforces lifetime safety at compile time:

**Option 1 - Use RAII wrapper (C++):**
```cpp
#include <memory>
#include <string>

void safe_version() {
    auto data = std::make_unique<char[]>(100);
    memset(data.get(), 'A', 99);
    data[99] = '\0';
    printLine(data.get());
    // Automatic cleanup, no dangling pointer possible after scope exit
}
```

**Option 2 - Nullify after free pattern (C):**
```c
#define SAFE_FREE(ptr) do { free(ptr); (ptr) = NULL; } while(0)

void safer_version() {
    char * data = (char *)malloc(100*sizeof(char));
    if (data == NULL) {exit(-1);}
    memset(data, 'A', 99);
    data[99] = '\0';

    printLine(data);
    SAFE_FREE(data);

    // Any subsequent use would dereference NULL, 
    // causing immediate crash rather than UB
    if (data) {  // This check would prevent use-after-free
        printLine(data);
    }
}
```

**Option 3 - Borrow checker pattern / Ownership transfer
Redes:**ign the API so that ownership and lifetime are explicit:
```c
// Takes ownership and frees the data
void printLineAndFree(char *data) {
    if (data != NULL) {
        printf("%s\n", data);
        free(data);
    }
}

void safe_version() {
    char * data = (char *)malloc(100*sizeof(char));
    if (data == NULL) {exit(-1);}
    memset(data, 'A', 99);
    data[99] = '\0';

    // Transfer ownership - caller knows not to use data afterward
    printLineAndFree(data);
    // data is now conceptually invalid
}
```

**Option 4 - Static analysis + annotations:**
Use static analysis tools with ownership annotations (e.g., Clang's static analyzer with annotations, or adopt a subset of C that supports ownership like Checked C) to catch use-after-free at compile time rather than runtime.

